// app/assets/javascript/comparison.js
document.getElementById("compare-form").addEventListener("submit", function(e) {
  const checkboxes = document.querySelectorAll(".compare-checkboxes__input:checked");
  const error = document.getElementById("checkboxError");
  const formGroup = document.querySelector(".compareGroup");
  if (checkboxes.length !== 2) {
    e.preventDefault();
    error.style.display = "block";
    formGroup.classList.add("nhsuk-form-group--error");
  } else {
    error.style.display = "none";
    formGroup.classList.remove("nhsuk-form-group--error");
  }
});
var details = document.getElementById("compareDetails");
document.querySelectorAll(".check-btn").forEach((button) => {
  button.addEventListener("click", function() {
    const targetId = this.dataset.target;
    const checkbox = document.getElementById(targetId);
    if (!checkbox) return;
    details.open = true;
    details.scrollIntoView({ behavior: "smooth", block: "center" });
    document.querySelectorAll('#myDetails input[type="checkbox"]').forEach((cb) => cb.checked = false);
    checkbox.checked = true;
  });
});
